import React, { useEffect, useState } from "react";
import { X, Calendar, ChevronDown, Search } from "lucide-react";
import "./Dashboard.css";
import "../../App.css";
import FilterMember from "../../components/common/FilterMember.js";
import { useNavigate } from "react-router-dom";
import api from "../../api";

function CreatePage() {
  const [leaders, setLeaders] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [assignedMembers, setAssignedMembers] = useState([]);
  const [title, setTitle] = useState("");
  const [crimeDate, setCrimeDate] = useState("");
  const [description, setDescription] = useState("");
  const [leader, setLeader] = useState("");
  const [priority, setPriority] = useState("High");
  const [status, setStatus] = useState("Open");

  const priorities = ["High", "Medium", "Low"];
  const statuses = ["Open", "Closed", "Archived"];
  const navigate = useNavigate();

  const handleSearch = async (e) => {
    const value = e.target.value;
    setSearchTerm(value);

    if (value.length >= 1) {
      try {
        const res = await api.get(`/users/search?q=${value}`);
        setSearchResults(Array.isArray(res.data) ? res.data : []);
      } catch (err) {
        console.error("Error searching users:", err);
        setSearchResults([]);
      }
    } else {
      setSearchResults([]);
    }
  };

  const addMember = (member) => {
    if (!assignedMembers.find((m) => m._id === member._id)) {
      setAssignedMembers([...assignedMembers, member]);
    }
    setSearchTerm("");
    setSearchResults([]);
  };

  const removeMember = (id) => {
    setAssignedMembers(assignedMembers.filter((m) => m._id !== id));
  };

  const parseDate = (dateStr) => {
    const [day, month, year] = dateStr.split("/").map(Number);
    const fullYear = year < 100 ? 2000 + year : year;
    return new Date(fullYear, month - 1, day);
  };


  const handleCreateCase = async () => {
    if (!title.trim()) {
      alert("Please enter case title");
      return;
    }

    if (!description.trim()) {
      alert("Please enter description");
      return;
    }

    if (!leader) {
      alert("Please select a leader");
      return;
    }

    let formattedDate = new Date();

    if (crimeDate) {
      try {
        formattedDate = parseDate(crimeDate);
      } catch {
        alert("Invalid date format (use DD/MM/YYYY)");
        return;
      }
    }

    const caseDetails = {
      title,
      description,
      status,
      priority,
      start_date: formattedDate.toISOString(),
      leader_id: leader,
      member_ids: assignedMembers.map((m) => m._id),
    };

    try {
      const res = await api.post("/create-case", caseDetails);
      console.log("Case created:", res.data);

      alert("Case created successfully!");
      navigate("/dashboard");
    } catch (err) {
      console.error("Error creating case:", err);
      alert(err.response?.data?.message || "Failed to create case");
    }
  };

  useEffect(() => {
    api
      .get("/users/leads")
      .then((res) => setLeaders(res.data))
      .catch((err) => console.error("Error fetching leads:", err));
  }, []);

  const handleFilterSelection = async (selected) => {
    if (!selected) {
      setSearchResults([]);
      return;
    }

    try {
      const res = await api.get(`/users/filter?q=${selected}`);
      setSearchResults(Array.isArray(res.data) ? res.data : []);
      setSearchTerm("");
    } catch (err) {
      console.error("Error fetching filtered users:", err);
      setSearchResults([]);
    }
  };

  return (
    <div className="mainContentArea dashboard-bg">
      <div className="createPageWrapper">
        <header className="pageHeader">
          <h1>Create New Case</h1>
          <p>Enter case details and assign the team.</p>
        </header>

        <div className="formStack">
          {/* Case Details */}
          <section className="formSectionCard">
            <div className="sectionHeader">
              <div className="indicatorDot" />
              <h2>Case Details</h2>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Case Title</label>
                <input
                  type="text"
                  placeholder="Bank Robbery"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                />
              </div>

              <div className="inputGroup">
                <label>Crime Location</label>
                <div className="selectWrapper">
                  <select>
                    <option>Pune</option>
                  </select>
                  <ChevronDown className="dropdownIcon" size={16} />
                </div>
              </div>

              <div className="inputGroup">
                <label>Date of Crime</label>
                <div className="iconInputWrapper">
                  <input
                    type="text"
                    placeholder="12/03/2026"
                    value={crimeDate}
                    onChange={(e) => setCrimeDate(e.target.value)}
                  />
                  <Calendar className="inputInnerIcon" size={18} />
                </div>
              </div>

              <div className="inputGroup fullRow">
                <label>Description</label>
                <textarea
                  rows="4"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                />
              </div>
            </div>
          </section>

          {/* Assignment */}
          <section className="formSectionCard">
            <div className="sectionHeader flexSpaceBetween">
              <div className="flexCenter gap2">
                <div className="indicatorDot" />
                <h2>Assignment</h2>
              </div>

              <div className="headerToolbox">
                <div className="searchBox">
                  <Search size={16} />
                  <input
                    type="text"
                    placeholder="Search team..."
                    value={searchTerm}
                    onChange={handleSearch}
                  />

                  {searchResults.length > 0 && (
                    <div className="searchDropdown">
                      {searchResults.map((member) => (
                        <div
                          key={member._id}
                          className="searchItem"
                          onClick={() => addMember(member)}
                        >
                          {member.name}
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                <FilterMember onFilterSelect={handleFilterSelection} />
              </div>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Assigned Leader</label>
                <div className="selectWrapper">
                  <select
                    value={leader}
                    onChange={(e) => setLeader(e.target.value)}
                  >
                    <option value="">Select a leader</option>
                    {leaders.map((l) => (
                      <option key={l._id} value={l._id}>
                        {l.name}
                      </option>
                    ))}
                  </select>
                  <ChevronDown size={16} />
                </div>
              </div>

              <div className="inputGroup">
                <label>Team Members</label>
                <div className="tagDisplayArea">
                  {assignedMembers.map((member) => (
                    <span key={member._id} className="memberTag">
                      {member.name}
                      <X
                        size={14}
                        onClick={() => removeMember(member._id)}
                      />
                    </span>
                  ))}
                </div>
              </div>
            </div>
          </section>

          {/* Settings */}
          <section className="formSectionCard">
            <div className="sectionHeader">
              <div className="indicatorDot" />
              <h2>Case Settings</h2>
            </div>

            <div className="formGrid">
              <div className="inputGroup">
                <label>Priority</label>
                <select
                  value={priority}
                  onChange={(e) => setPriority(e.target.value)}
                >
                  {priorities.map((p) => (
                    <option key={p}>{p}</option>
                  ))}
                </select>
              </div>

              <div className="inputGroup">
                <label>Status</label>
                <select
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                >
                  {statuses.map((s) => (
                    <option key={s}>{s}</option>
                  ))}
                </select>
              </div>
            </div>
          </section>

          <footer className="formFooter">
            <button onClick={() => navigate("/dashboard")}>Cancel</button>
            <button onClick={handleCreateCase}>Create Case</button>
          </footer>
        </div>
      </div>
    </div>
  );
}

export default CreatePage;
